const nextConfig: NextConfig = {
  reactCompiler: true,
};

export default nextConfig;

import { defineConfig } from 'vitest/config';
import react from '@vitejs/plugin-react';
import path from 'path';

export default defineConfig({
  plugins: [react()],
  test: {
    environment: 'happy-dom',
    globals: true,
    setupFiles: ['./tests/setup.ts'],
    exclude: ['node_modules', '.next', 'tests/e2e/**'],
    coverage: {
      provider: 'v8',
      reporter: ['text', 'json', 'html', 'lcov'],
      exclude: [
        'node_modules/',
        'tests/',
        '**/*.d.ts',
        '**/*.config.*',
        '**/generated/**',
        'app/layout.tsx',
        'app/globals.css',
      ],
      thresholds: {
        lines: 80,
        functions: 80,
        branches: 80,
        statements: 80,
      },
    },
  },
  resolve: {
    alias: {
      '@': path.resolve(__dirname, './'),
      '@/app/generated/prisma': path.resolve(__dirname, './app/generated/prisma'),
      '@/app/generated/prisma/client': path.resolve(__dirname, './app/generated/prisma/client'),
    },
  },
});

import { getTodos } from './actions/todos';
import { getCurrentUser } from '@/lib/auth';
import TodoList from './components/TodoList';
import TodoForm from './components/TodoForm';
import { UserMenu } from './components/auth/UserMenu';

export default async function Home() {
  const [result, user] = await Promise.all([
    getTodos(),
    getCurrentUser(),
  ]);
  const todos = result.success && result.data ? result.data : [];

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100">
      <div className="container mx-auto px-4 py-8 max-w-4xl">
        <header className="mb-8 flex items-start justify-between">
          <div>
            <h1 className="text-4xl font-bold text-gray-900 mb-2">My Todo List</h1>
            <p className="text-gray-700">Stay organized and productive</p>
          </div>
          {user && <UserMenu user={user} />}
        </header>

        <div className="grid gap-6 md:grid-cols-2">
          <div className="bg-white rounded-lg shadow-md p-6">
            <h2 className="text-xl font-semibold mb-4 text-gray-800">Add New Todo</h2>
            <TodoForm />
          </div>

          <div className="bg-white rounded-lg shadow-md p-6">
            <h2 className="text-xl font-semibold mb-4 text-gray-800">Your Todos</h2>
            <TodoList todos={todos} />
          </div>
        </div>
      </div>
    </div>
  );
}

